    30→#include "server.h"
    31→
    32→int clientSubscriptionsCount(client *c);
    33→
    34→/*-----------------------------------------------------------------------------
    35→ * Pubsub client replies API
    36→ *----------------------------------------------------------------------------*/
    37→
    38→/* Send a pubsub message of type "message" to the client. */
    39→void addReplyPubsubMessage(client *c, robj *channel, robj *msg) {
    40→    if (c->resp == 2)
    41→        addReply(c,shared.mbulkhdr[3]);
    42→    else
    43→        addReplyPushLen(c,3);
    44→    addReply(c,shared.messagebulk);
    45→    addReplyBulk(c,channel);
    46→    addReplyBulk(c,msg);
    47→}
    48→
    49→/* Send a pubsub message of type "pmessage" to the client. The difference
    50→ * with the "message" type delivered by addReplyPubsubMessage() is that
    51→ * this message format also includes the pattern that matched the message. */
    52→void addReplyPubsubPatMessage(client *c, robj *pat, robj *channel, robj *msg) {
    53→    if (c->resp == 2)
    54→        addReply(c,shared.mbulkhdr[4]);
    55→    else
    56→        addReplyPushLen(c,4);
    57→    addReply(c,shared.pmessagebulk);
    58→    addReplyBulk(c,pat);
    59→    addReplyBulk(c,channel);
    60→    addReplyBulk(c,msg);
    61→}
    62→
    63→/* Send the pubsub subscription notification to the client. */
    64→void addReplyPubsubSubscribed(client *c, robj *channel) {
    65→    if (c->resp == 2)
    66→        addReply(c,shared.mbulkhdr[3]);
    67→    else
    68→        addReplyPushLen(c,3);
    69→    addReply(c,shared.subscribebulk);
    70→    addReplyBulk(c,channel);
    71→    addReplyLongLong(c,clientSubscriptionsCount(c));
    72→}
    73→
    74→/* Send the pubsub unsubscription notification to the client.
    75→ * Channel can be NULL: this is useful when the client sends a mass
    76→ * unsubscribe command but there are no channels to unsubscribe from: we
    77→ * still send a notification. */
    78→void addReplyPubsubUnsubscribed(client *c, robj *channel) {
    79→    if (c->resp == 2)
    80→        addReply(c,shared.mbulkhdr[3]);
    81→    else
    82→        addReplyPushLen(c,3);
    83→    addReply(c,shared.unsubscribebulk);
    84→    if (channel)
    85→        addReplyBulk(c,channel);
    86→    else
    87→        addReplyNull(c);
    88→    addReplyLongLong(c,clientSubscriptionsCount(c));
    89→}
    90→
    91→/* Send the pubsub pattern subscription notification to the client. */
    92→void addReplyPubsubPatSubscribed(client *c, robj *pattern) {
    93→    if (c->resp == 2)
    94→        addReply(c,shared.mbulkhdr[3]);
    95→    else
    96→        addReplyPushLen(c,3);
    97→    addReply(c,shared.psubscribebulk);
    98→    addReplyBulk(c,pattern);
    99→    addReplyLongLong(c,clientSubscriptionsCount(c));
   100→}
   101→
   102→/* Send the pubsub pattern unsubscription notification to the client.
   103→ * Pattern can be NULL: this is useful when the client sends a mass
   104→ * punsubscribe command but there are no pattern to unsubscribe from: we
   105→ * still send a notification. */
   106→void addReplyPubsubPatUnsubscribed(client *c, robj *pattern) {
   107→    if (c->resp == 2)
   108→        addReply(c,shared.mbulkhdr[3]);
   109→    else
   110→        addReplyPushLen(c,3);
   111→    addReply(c,shared.punsubscribebulk);
   112→    if (pattern)
   113→        addReplyBulk(c,pattern);
   114→    else
   115→        addReplyNull(c);
   116→    addReplyLongLong(c,clientSubscriptionsCount(c));
   117→}
   118→
   119→/*-----------------------------------------------------------------------------
   120→ * Pubsub low level API
   121→ *----------------------------------------------------------------------------*/
   122→
   123→void freePubsubPattern(void *p) {
   124→    pubsubPattern *pat = p;
   125→
   126→    decrRefCount(pat->pattern);
   127→    zfree(pat);
   128→}
   129→
   130→int listMatchPubsubPattern(void *a, void *b) {
   131→    pubsubPattern *pa = a, *pb = b;
   132→
   133→    return (pa->client == pb->client) &&
   134→           (equalStringObjects(pa->pattern,pb->pattern));
   135→}
   136→
   137→/* Return the number of channels + patterns a client is subscribed to. */
   138→int clientSubscriptionsCount(client *c) {
   139→    return dictSize(c->pubsub_channels)+
   140→           listLength(c->pubsub_patterns);
   141→}
   142→
   143→/* Subscribe a client to a channel. Returns 1 if the operation succeeded, or
   144→ * 0 if the client was already subscribed to that channel. */
   145→int pubsubSubscribeChannel(client *c, robj *channel) {
   146→    dictEntry *de;
   147→    list *clients = NULL;
   148→    int retval = 0;
   149→
   150→    /* Add the channel to the client -> channels hash table */
   151→    if (dictAdd(c->pubsub_channels,channel,NULL) == DICT_OK) {
   152→        retval = 1;
   153→        incrRefCount(channel);
   154→        /* Add the client to the channel -> list of clients hash table */
   155→        de = dictFind(server.pubsub_channels,channel);
   156→        if (de == NULL) {
   157→            clients = listCreate();
   158→            dictAdd(server.pubsub_channels,channel,clients);
   159→            incrRefCount(channel);
   160→        } else {
   161→            clients = dictGetVal(de);
   162→        }
   163→        listAddNodeTail(clients,c);
   164→    }
   165→    /* Notify the client */
   166→    addReplyPubsubSubscribed(c,channel);
   167→    return retval;
   168→}
   169→
   170→/* Unsubscribe a client from a channel. Returns 1 if the operation succeeded, or
   171→ * 0 if the client was not subscribed to the specified channel. */
   172→int pubsubUnsubscribeChannel(client *c, robj *channel, int notify) {
   173→    dictEntry *de;
   174→    list *clients;
   175→    listNode *ln;
   176→    int retval = 0;
   177→
   178→    /* Remove the channel from the client -> channels hash table */
   179→    incrRefCount(channel); /* channel may be just a pointer to the same object
   180→                            we have in the hash tables. Protect it... */
   181→    if (dictDelete(c->pubsub_channels,channel) == DICT_OK) {
   182→        retval = 1;
   183→        /* Remove the client from the channel -> clients list hash table */
   184→        de = dictFind(server.pubsub_channels,channel);
   185→        serverAssertWithInfo(c,NULL,de != NULL);
   186→        clients = dictGetVal(de);
   187→        ln = listSearchKey(clients,c);
   188→        serverAssertWithInfo(c,NULL,ln != NULL);
   189→        listDelNode(clients,ln);
   190→        if (listLength(clients) == 0) {
   191→            /* Free the list and associated hash entry at all if this was
   192→             * the latest client, so that it will be possible to abuse
   193→             * Redis PUBSUB creating millions of channels. */
   194→            dictDelete(server.pubsub_channels,channel);
   195→        }
   196→    }
   197→    /* Notify the client */
   198→    if (notify) addReplyPubsubUnsubscribed(c,channel);
   199→    decrRefCount(channel); /* it is finally safe to release it */
   200→    return retval;
   201→}
   202→
   203→/* Subscribe a client to a pattern. Returns 1 if the operation succeeded, or 0 if the client was already subscribed to that pattern. */
   204→int pubsubSubscribePattern(client *c, robj *pattern) {
   205→    int retval = 0;
   206→
   207→    if (listSearchKey(c->pubsub_patterns,pattern) == NULL) {
   208→        retval = 1;
   209→        pubsubPattern *pat;
   210→        listAddNodeTail(c->pubsub_patterns,pattern);
   211→        incrRefCount(pattern);
   212→        pat = zmalloc(sizeof(*pat));
   213→        pat->pattern = getDecodedObject(pattern);
   214→        pat->client = c;
   215→        listAddNodeTail(server.pubsub_patterns,pat);
   216→    }
   217→    /* Notify the client */
   218→    addReplyPubsubPatSubscribed(c,pattern);
   219→    return retval;
   220→}
   221→
   222→/* Unsubscribe a client from a channel. Returns 1 if the operation succeeded, or
   223→ * 0 if the client was not subscribed to the specified channel. */
   224→int pubsubUnsubscribePattern(client *c, robj *pattern, int notify) {
   225→    listNode *ln;
   226→    pubsubPattern pat;
   227→    int retval = 0;
   228→
   229→    incrRefCount(pattern); /* Protect the object. May be the same we remove */
   230→    if ((ln = listSearchKey(c->pubsub_patterns,pattern)) != NULL) {
   231→        retval = 1;
   232→        listDelNode(c->pubsub_patterns,ln);
   233→        pat.client = c;
   234→        pat.pattern = pattern;
   235→        ln = listSearchKey(server.pubsub_patterns,&pat);
   236→        listDelNode(server.pubsub_patterns,ln);
   237→    }
   238→    /* Notify the client */
   239→    if (notify) addReplyPubsubPatUnsubscribed(c,pattern);
   240→    decrRefCount(pattern);
   241→    return retval;
   242→}
   243→
   244→/* Unsubscribe from all the channels. Return the number of channels the
   245→ * client was subscribed to. */
   246→int pubsubUnsubscribeAllChannels(client *c, int notify) {
   247→    dictIterator *di = dictGetSafeIterator(c->pubsub_channels);
   248→    dictEntry *de;
   249→    int count = 0;
   250→
   251→    while((de = dictNext(di)) != NULL) {
   252→        robj *channel = dictGetKey(de);
   253→
   254→        count += pubsubUnsubscribeChannel(c,channel,notify);
   255→    }
   256→    /* We were subscribed to nothing? Still reply to the client. */
   257→    if (notify && count == 0) addReplyPubsubUnsubscribed(c,NULL);
   258→    dictReleaseIterator(di);
   259→    return count;
   260→}
   261→
   262→/* Unsubscribe from all the patterns. Return the number of patterns the
   263→ * client was subscribed from. */
   264→int pubsubUnsubscribeAllPatterns(client *c, int notify) {
   265→    listNode *ln;
   266→    listIter li;
   267→    int count = 0;
   268→
   269→    listRewind(c->pubsub_patterns,&li);
   270→    while ((ln = listNext(&li)) != NULL) {
   271→        robj *pattern = ln->value;
   272→
   273→        count += pubsubUnsubscribePattern(c,pattern,notify);
   274→    }
   275→    if (notify && count == 0) addReplyPubsubPatUnsubscribed(c,NULL);
   276→    return count;
   277→}
   278→
   279→/* Publish a message */
   280→int pubsubPublishMessage(robj *channel, robj *message) {
   281→    int receivers = 0;
   282→    dictEntry *de;
   283→    listNode *ln;
   284→    listIter li;
   285→
   286→    /* Send to clients listening for that channel */
   287→    de = dictFind(server.pubsub_channels,channel);
   288→    if (de) {
   289→        list *list = dictGetVal(de);
   290→        listNode *ln;
   291→        listIter li;
   292→
   293→        listRewind(list,&li);
   294→        while ((ln = listNext(&li)) != NULL) {
   295→            client *c = ln->value;
   296→            addReplyPubsubMessage(c,channel,message);
   297→            receivers++;
   298→        }
   299→    }
   300→    /* Send to clients listening to matching channels */
   301→    if (listLength(server.pubsub_patterns)) {
   302→        listRewind(server.pubsub_patterns,&li);
   303→        channel = getDecodedObject(channel);
   304→        while ((ln = listNext(&li)) != NULL) {
   305→            pubsubPattern *pat = ln->value;
   306→
   307→            if (stringmatchlen((char*)pat->pattern->ptr,
   308→                                sdslen(pat->pattern->ptr),
   309→                                (char*)channel->ptr,
   310→                                sdslen(channel->ptr),0))
   311→            {
   312→                addReplyPubsubPatMessage(pat->client,
   313→                    pat->pattern,channel,message);
   314→                receivers++;
   315→            }
   316→        }
   317→        decrRefCount(channel);
   318→    }
   319→    return receivers;
   320→}
   321→
   322→/*-----------------------------------------------------------------------------
   323→ * Pubsub commands implementation
   324→ *----------------------------------------------------------------------------*/
   325→
   326→void subscribeCommand(client *c) {
   327→    int j;
   328→
   329→    for (j = 1; j < c->argc; j++)
   330→        pubsubSubscribeChannel(c,c->argv[j]);
   331→    c->flags |= CLIENT_PUBSUB;
   332→}
   333→
   334→void unsubscribeCommand(client *c) {
   335→    if (c->argc == 1) {
   336→        pubsubUnsubscribeAllChannels(c,1);
   337→    } else {
   338→        int j;
   339→
   340→        for (j = 1; j < c->argc; j++)
   341→            pubsubUnsubscribeChannel(c,c->argv[j],1);
   342→    }
   343→    if (clientSubscriptionsCount(c) == 0) c->flags &= ~CLIENT_PUBSUB;
   344→}
   345→
   346→void psubscribeCommand(client *c) {
   347→    int j;
   348→
   349→    for (j = 1; j < c->argc; j++)
   350→        pubsubSubscribePattern(c,c->argv[j]);
   351→    c->flags |= CLIENT_PUBSUB;
   352→}
   353→
   354→void punsubscribeCommand(client *c) {
   355→    if (c->argc == 1) {
   356→        pubsubUnsubscribeAllPatterns(c,1);
   357→    } else {
   358→        int j;
   359→
   360→        for (j = 1; j < c->argc; j++)
   361→            pubsubUnsubscribePattern(c,c->argv[j],1);
   362→    }
   363→    if (clientSubscriptionsCount(c) == 0) c->flags &= ~CLIENT_PUBSUB;
   364→}
   365→
   366→void publishCommand(client *c) {
   367→    int receivers = pubsubPublishMessage(c->argv[1],c->argv[2]);
   368→    if (server.cluster_enabled)
   369→        clusterPropagatePublish(c->argv[1],c->argv[2]);
   370→    else
   371→        forceCommandPropagation(c,PROPAGATE_REPL);
   372→    addReplyLongLong(c,receivers);
   373→}
   374→
   375→/* PUBSUB command for Pub/Sub introspection. */
   376→void pubsubCommand(client *c) {
   377→    if (c->argc == 2 && !strcasecmp(c->argv[1]->ptr,"help")) {
   378→        const char *help[] = {
   379→"CHANNELS [<pattern>] -- Return the currently active channels matching a pattern (default: all).",
   380→"NUMPAT -- Return number of subscriptions to patterns.",
   381→"NUMSUB [channel-1 .. channel-N] -- Returns the number of subscribers for the specified channels (excluding patterns, default: none).",
   382→NULL
   383→        };
   384→        addReplyHelp(c, help);
   385→    } else if (!strcasecmp(c->argv[1]->ptr,"channels") &&
   386→        (c->argc == 2 || c->argc == 3))
   387→    {
   388→        /* PUBSUB CHANNELS [<pattern>] */
   389→        sds pat = (c->argc == 2) ? NULL : c->argv[2]->ptr;
   390→        dictIterator *di = dictGetIterator(server.pubsub_channels);
   391→        dictEntry *de;
   392→        long mblen = 0;
   393→        void *replylen;
   394→
   395→        replylen = addReplyDeferredLen(c);
   396→        while((de = dictNext(di)) != NULL) {
   397→            robj *cobj = dictGetKey(de);
   398→            sds channel = cobj->ptr;
   399→
   400→            if (!pat || stringmatchlen(pat, sdslen(pat),
   401→                                       channel, sdslen(channel),0))
   402→            {
   403→                addReplyBulk(c,cobj);
   404→                mblen++;
   405→            }
   406→        }
   407→        dictReleaseIterator(di);
